using BoutiqueInventoryAPI.Data; using BoutiqueInventoryAPI.DTOs; using BoutiqueInventoryAPI.Services; using Microsoft.AspNetCore.Mvc; using Microsoft.EntityFrameworkCore;
namespace BoutiqueInventoryAPI.Controllers;
[ApiController][Route("api/[controller]")] public class CategoriesController:ControllerBase{private readonly BoutiqueDbContext _context; private readonly IStoredProcedureService _spService; public CategoriesController(BoutiqueDbContext context,IStoredProcedureService spService){_context=context;_spService=spService;} [HttpGet] public async Task<IActionResult> GetAll(){return Ok(await _context.Categories.ToListAsync());} [HttpGet("{id}")] public async Task<IActionResult> GetById(int id){var c=await _context.Categories.FindAsync(id); return c==null?NotFound("Category not found."):Ok(c);} [HttpPost] public async Task<IActionResult> Create(CategoryCreateDto dto){var id=await _spService.InsertCategoryAsync(dto); var c=await _context.Categories.FindAsync(id); return CreatedAtAction(nameof(GetById),new{id},c);} [HttpPut("{id}")] public async Task<IActionResult> Update(int id,CategoryUpdateDto dto){await _spService.UpdateCategoryAsync(id,dto); var c=await _context.Categories.FindAsync(id); return c==null?NotFound("Category not found."):Ok(c);} [HttpDelete("{id}")] public async Task<IActionResult> Delete(int id){var c=await _context.Categories.FindAsync(id); if(c==null)return NotFound("Category not found."); _context.Categories.Remove(c); await _context.SaveChangesAsync(); return Ok("Category deleted successfully.");}}
